test-case.copilot-command:
$computers = Get-Content "C:\servers.txt"
foreach ($computer in $computers) {
    try {
        $regVal = Get-ItemProperty -Path "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion" `
            -ComputerName $computer -ErrorAction Stop
        Write-Host "$computer : $($regVal.ProductName)"
    }
    catch [System.UnauthorizedAccessException] {
        Write-Warning "Access denied on $computer"
    }
    catch {
        Write-Warning "Failed to connect to $computer : $_"
    }
}

Invoke-Command -ComputerName "DC01", "DC02" -ScriptBlock {
    Get-CimInstance -ClassName Win32_LogicalDisk -Filter "DriveType=3" |
        Select-Object DeviceID, VolumeName, @{
            Name='FreeSpaceGB'
            Expression={[math]::Round($_.FreeSpace/1GB, 2)}
        }, @{
            Name='TotalSpaceGB'
            Expression={[math]::Round($_.Size/1GB, 2)}
        } | Format-Table -AutoSize
}

Invoke-Command -ComputerName (Get-Content "C:\serverlist.txt") -ScriptBlock {
    $packagePath = "\\fileserver\installs\app.msi"
    if (Test-Path $packagePath) {
        Start-Process -FilePath "msiexec.exe" -ArgumentList "/i `"$packagePath`" /qn /norestart" -Wait
        Write-Host "Package installed on $env:COMPUTERNAME" -ForegroundColor Green
    }
    else {
        Write-Warning "Package not found at $packagePath"
    }
}
